    """
    Manages AI model selection, fallback, and rate limits.
    Implements an agent-based approach for model management.
    """

    MODEL_CONFIG = {
        ModelTier.PRIMARY: {
            "provider": "groq",
            "model": "meta-llama/llama-4-maverick-17b-128e-instruct",
            "max_tokens": 2000,
